SELECT b.*, ste.site_nm AS site_nm, cd_bc.code_label AS batch_cycle_cd_nm, cd_bs.code_label AS batch_status_cd_nm FROM sy_batch b LEFT JOIN sy_site ste ON ste.site_id = b.site_id LEFT JOIN sy_code cd_bc ON cd_bc.code_grp = 'BATCH_CYCLE' AND cd_bc.code_value = b.batch_cycle_cd LEFT JOIN sy_code cd_bs ON cd_bs.code_grp = 'BATCH_STATUS' AND cd_bs.code_value = b.batch_status_cd
ORDER BY b.batch_id ASC ORDER BY b.batch_id DESC ORDER BY b.batch_nm ASC ORDER BY b.batch_nm DESC ORDER BY b.reg_date ASC ORDER BY b.reg_date DESC ORDER BY b.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

